import{_ as e,o as r,c as o,a2 as d}from"./chunks/framework.CHSDihme.js";const u=JSON.parse('{"title":"Claude Code 记忆系统文档","description":"","frontmatter":{},"headers":[],"relativePath":"memory/index.md","filePath":"memory/index.md","lastUpdated":1780729781000}'),a={name:"memory/index.md"};function i(l,t,n,s,c,m){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="claude-code-记忆系统文档" tabindex="-1">Claude Code 记忆系统文档 <a class="header-anchor" href="#claude-code-记忆系统文档" aria-label="Permalink to &quot;Claude Code 记忆系统文档&quot;">​</a></h1><blockquote><p>完整的记忆系统使用指南和实现原理文档</p></blockquote><hr><h2 id="-文档目录" tabindex="-1">📚 文档目录 <a class="header-anchor" href="#-文档目录" aria-label="Permalink to &quot;📚 文档目录&quot;">​</a></h2><h3 id="01-usage-guidemd--使用指南" tabindex="-1"><a href="./01-usage-guide.html">01-usage-guide.md</a> — 使用指南 <a class="header-anchor" href="#01-usage-guidemd--使用指南" aria-label="Permalink to &quot;[01-usage-guide.md](./01-usage-guide.md) — 使用指南&quot;">​</a></h3><p>面向用户的完整使用手册，涵盖：</p><ul><li><strong>四种记忆类型</strong>：User（用户画像）、Feedback（行为反馈）、Project（项目动态）、Reference（外部引用）</li><li><strong>四种触发方式</strong>：自动提取、显式请求、<code>/memory</code> 命令、<code>/remember</code> 命令</li><li><strong>存储格式</strong>：YAML frontmatter + Markdown 内容</li><li><strong>管理操作</strong>：遗忘、忽略、手动编辑、禁用、自定义目录</li><li><strong>生命周期</strong>：从学习到注入，新鲜度管理</li></ul><p><strong>适合人群</strong>：所有 Claude Code 用户</p><hr><h3 id="02-implementationmd--实现原理" tabindex="-1"><a href="./02-implementation.html">02-implementation.md</a> — 实现原理 <a class="header-anchor" href="#02-implementationmd--实现原理" aria-label="Permalink to &quot;[02-implementation.md](./02-implementation.md) — 实现原理&quot;">​</a></h3><p>面向开发者的技术深度解析，涵盖：</p><ul><li><strong>5 大核心模块</strong>：路径解析、提示词构建、记忆扫描、智能检索、自动提取</li><li><strong>路径解析系统</strong>：优先级链、安全校验、启用条件</li><li><strong>系统提示词注入</strong>：<code>loadMemoryPrompt()</code> → <code>buildMemoryLines()</code>，MEMORY.md 截断策略</li><li><strong>自动记忆提取</strong>：分叉代理、互斥机制、工具权限、合并机制</li><li><strong>智能检索</strong>：<code>scanMemoryFiles()</code> → Sonnet 选择 → 新鲜度警告</li><li><strong>代理记忆</strong>：三级作用域（user/project/local）</li><li><strong>团队记忆同步</strong>：Pull/Push API、合并语义</li><li><strong>完整数据流</strong>：从会话启动到上下文注入</li></ul><p><strong>适合人群</strong>：贡献者、架构师、想深入了解实现的开发者</p><hr><h3 id="03-autodreammd--autodream-记忆整合" tabindex="-1"><a href="./03-autodream.html">03-autodream.md</a> — AutoDream 记忆整合 <a class="header-anchor" href="#03-autodreammd--autodream-记忆整合" aria-label="Permalink to &quot;[03-autodream.md](./03-autodream.md) — AutoDream 记忆整合&quot;">​</a></h3><p>Claude 的&quot;做梦&quot;机制——后台静默整合记忆的深度解析，涵盖：</p><ul><li><strong>核心概念</strong>：像人类睡眠整理记忆一样，定期回顾多个会话整合知识</li><li><strong>五重门控</strong>：功能开关 → 时间门控(24h) → 扫描节流(10min) → 会话门控(5个) → 锁门控</li><li><strong>四阶段流程</strong>：Orient（定向）→ Gather（收集）→ Consolidate（整合）→ Prune（修剪）</li><li><strong>安全限制</strong>：Bash 只读、写操作仅限记忆目录、PID 锁文件互斥</li><li><strong>UI 展示</strong>：底部 &quot;dreaming&quot; 标签、Shift+Down 详情对话框、完成通知</li><li><strong>配置控制</strong>：settings.json 本地开关 + GrowthBook 远程 feature flag</li><li><strong>与 extractMemories 对比</strong>：白天记笔记 vs 睡觉整理笔记本</li></ul><p><strong>适合人群</strong>：贡献者、架构师、对 Claude 自动化记忆管理感兴趣的开发者</p><hr><h2 id="️-配图说明" tabindex="-1">🖼️ 配图说明 <a class="header-anchor" href="#️-配图说明" aria-label="Permalink to &quot;🖼️ 配图说明&quot;">​</a></h2><p>所有配图采用深色背景（#1a1a2e）+ Anthropic 品牌橙铜色（#D97757）风格，与 Claude Code 官方文档一致。</p><table tabindex="0"><thead><tr><th>图片</th><th>说明</th><th>尺寸</th></tr></thead><tbody><tr><td><code>01-memory-overview.png</code></td><td>记忆系统概览 — 四层架构（触发/类型/存储/检索）</td><td>632 KB</td></tr><tr><td><code>02-memory-types.png</code></td><td>四种记忆类型 — 2x2 网格展示 User/Feedback/Project/Reference</td><td>507 KB</td></tr><tr><td><code>03-memory-trigger.png</code></td><td>记忆触发流程 — 从对话到存储的四种路径</td><td>474 KB</td></tr><tr><td><code>04-memory-lifecycle.png</code></td><td>记忆生命周期 — 完整循环流程 + 新鲜度判断</td><td>1.0 MB</td></tr><tr><td><code>05-architecture-overview.png</code></td><td>实现架构总览 — 5 个核心模块 + 辅助模块</td><td>3.5 MB</td></tr><tr><td><code>06-path-resolution.png</code></td><td>路径解析流程 — 三层优先级 + 安全校验</td><td>1.0 MB</td></tr><tr><td><code>07-prompt-injection.png</code></td><td>提示词注入流程 — loadMemoryPrompt 分发逻辑</td><td>1.1 MB</td></tr><tr><td><code>08-auto-extraction.png</code></td><td>自动提取流程 — 分叉代理完整流程</td><td>1.2 MB</td></tr><tr><td><code>09-memory-retrieval.png</code></td><td>智能检索流程 — Sonnet 选择 + 新鲜度管理</td><td>816 KB</td></tr><tr><td><code>10-agent-memory.png</code></td><td>代理记忆作用域 — 三级嵌套结构</td><td>523 KB</td></tr><tr><td><code>11-autodream-overview.png</code></td><td>AutoDream 概览 — 做梦机制的核心架构与人类睡眠类比</td><td>777 KB</td></tr><tr><td><code>12-autodream-trigger.png</code></td><td>AutoDream 触发流程 — 五重门控检查链</td><td>493 KB</td></tr><tr><td><code>13-autodream-phases.png</code></td><td>AutoDream 四阶段 — Orient/Gather/Consolidate/Prune</td><td>602 KB</td></tr></tbody></table><hr><h2 id="-快速开始" tabindex="-1">🚀 快速开始 <a class="header-anchor" href="#-快速开始" aria-label="Permalink to &quot;🚀 快速开始&quot;">​</a></h2><h3 id="用户" tabindex="-1">用户 <a class="header-anchor" href="#用户" aria-label="Permalink to &quot;用户&quot;">​</a></h3><ol><li>阅读 <a href="./01-usage-guide.html">使用指南</a></li><li>了解四种记忆类型和触发方式</li><li>尝试 <code>/memory</code> 和 <code>/remember</code> 命令</li></ol><h3 id="开发者" tabindex="-1">开发者 <a class="header-anchor" href="#开发者" aria-label="Permalink to &quot;开发者&quot;">​</a></h3><ol><li>阅读 <a href="./02-implementation.html">实现原理</a></li><li>查看源码位置： <ul><li><code>src/memdir/paths.ts</code> — 路径解析</li><li><code>src/memdir/memdir.ts</code> — 提示词构建</li><li><code>src/memdir/memoryScan.ts</code> — 记忆扫描</li><li><code>src/memdir/findRelevantMemories.ts</code> — 智能检索</li><li><code>src/services/extractMemories/</code> — 自动提取</li></ul></li><li>理解数据流和模块交互</li></ol><hr><h2 id="-核心概念速查" tabindex="-1">📝 核心概念速查 <a class="header-anchor" href="#-核心概念速查" aria-label="Permalink to &quot;📝 核心概念速查&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>说明</th></tr></thead><tbody><tr><td><strong>MEMORY.md</strong></td><td>索引文件，始终加载到上下文（最多 200 行 / 25KB）</td></tr><tr><td><strong>主题文件</strong></td><td><code>*.md</code> 文件，包含 frontmatter + 内容</td></tr><tr><td><strong>自动提取</strong></td><td>每次回复后后台运行，分叉代理分析对话</td></tr><tr><td><strong>AutoDream</strong></td><td>每 24h + 5 个会话后，后台整合/去重/修剪全部记忆</td></tr><tr><td><strong>智能检索</strong></td><td>Sonnet 模型从所有记忆中选择最多 5 个相关的</td></tr><tr><td><strong>新鲜度</strong></td><td>≤1 天无警告，&gt;1 天附带陈旧警告</td></tr><tr><td><strong>分叉代理</strong></td><td>共享提示词缓存，限制工具权限，最多 5 turns</td></tr><tr><td><strong>三级作用域</strong></td><td>代理记忆：user（全局）&gt; project（项目）&gt; local（本地）</td></tr></tbody></table><hr><h2 id="-相关资源" tabindex="-1">🔗 相关资源 <a class="header-anchor" href="#-相关资源" aria-label="Permalink to &quot;🔗 相关资源&quot;">​</a></h2><ul><li><a href="/claude-code-token-free/">Claude Code Token Free 主页</a></li><li><a href="https://hyqibot.github.io/claude-code-token-free//tree/main/src/memdir/" target="_blank" rel="noreferrer">记忆系统源码</a></li><li><a href="https://hyqibot.github.io/claude-code-token-free//tree/main/src/services/extractMemories/" target="_blank" rel="noreferrer">自动提取服务</a></li><li><a href="https://hyqibot.github.io/claude-code-token-free//tree/main/src/services/autoDream/" target="_blank" rel="noreferrer">AutoDream 服务</a></li><li><a href="https://hyqibot.github.io/claude-code-token-free//tree/main/src/tasks/DreamTask/" target="_blank" rel="noreferrer">DreamTask 任务</a></li><li><a href="https://hyqibot.github.io/claude-code-token-free//issues" target="_blank" rel="noreferrer">GitHub Issues</a></li></ul>',34)])])}const g=e(a,[["render",i]]);export{u as __pageData,g as default};
